import type { MarkedExtension, TokenizerAndRendererExtension } from 'marked';
/**
 * 流式缓存的 token 类型枚举。
 */
export declare enum StreamCacheTokenType {
    Text = "text",
    Link = "link",
    Image = "image",
    Html = "html",
    Emphasis = "emphasis",
    List = "list",
    Table = "table",
    InlineCode = "inline-code"
}
/**
 * 自定义子标签的状态：loading 表示流式过程中尚未闭合，done 表示已经闭合。
 */
export type StreamStatus = 'loading' | 'done';
/**
 * Parser 构造选项。
 */
export interface ParserOptions {
    /** 段落渲染所用的 HTML 标签，默认 'p'。 */
    paragraphTag?: keyof HTMLElementTagNameMap;
    /** 是否为所有链接添加 target="_blank"。 */
    openLinksInNewTab?: boolean;
    /** 是否将原始 HTML 转义为纯文本。 */
    escapeRawHtml?: boolean;
    /** 是否保护自定义子标签内部的换行（防止 marked 误解析为段落分隔）。 */
    protectCustomTagNewlines?: boolean;
    /** 用户自定义的 marked 扩展配置（最后注册，可覆盖内置 renderer）。 */
    markedConfig?: MarkedExtension;
    /** 已知的自定义子标签名列表，用于换行保护匹配。 */
    customTags?: readonly string[];
    /**
     * KaTeX 数学公式扩展（inline + block）。由 element 在启用 LaTeX 时按需动态引入并注入，
     * 使 katex 依赖不进入基础 chunk。
     */
    latexExtensions?: readonly TokenizerAndRendererExtension[];
}
/**
 * Renderer 构造选项。
 */
export interface RendererOptions {
    /** 已知的自定义子标签名列表（含内部依赖与用户自定义）。 */
    customTags?: readonly string[];
    /** 用户自定义的 DOMPurify 配置。 */
    dompurifyConfig?: SanitizeConfig;
}
/**
 * DOMPurify 配置的最小子集，避免直接依赖 dompurify 类型。
 */
export interface SanitizeConfig {
    ADD_TAGS?: string[];
    ADD_ATTR?: string[];
    FORBID_TAGS?: string[];
    FORBID_ATTR?: string[];
    ALLOWED_TAGS?: string[];
    ALLOWED_ATTR?: string[];
    ALLOWED_URI_REGEXP?: RegExp;
}
/**
 * 未闭合标签实例标识：`tagName-instanceIndex`，例如 `ve-md-mermaid-1`。
 */
export type UnclosedTagInstanceId = string;
/**
 * 检测未闭合自定义子标签的结果集合。
 */
export type UnclosedTagSet = Set<UnclosedTagInstanceId>;
